// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  ScrollView,
  Platform,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  // input text
  const [query, setQuery] = useState("Total borne 10 entre\nenfant noir chez le boss");

  // demo "resolved" payload (static for now; later you wire to API)
  const resolved = useMemo(() => {
    return {
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    };
  }, []);

  const onResolve = () => {
    // Later: call your /v1/lookup and set resolved state
    // For now: keep static
    console.log("Resolve:", query);
  };

  const onNavigate = () => {
    // Later: open maps with lat/lng
    // For now: placeholder
    console.log("Navigate to:", resolved.latitude, resolved.longitude);
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
      >
        <View style={styles.screen}>
          {/* Header */}
          <View style={styles.header}>
            <Image source={nalicoreLogo} style={styles.logo} resizeMode="contain" />
            <Text style={styles.tagline}>Natural Address{"\n"}Location Infrastructure</Text>
          </View>

          {/* Search + Resolve */}
          <View style={styles.searchRow}>
            <View style={styles.searchInputWrap}>
              <Text style={styles.searchIcon}>⌕</Text>
              <TextInput
                value={query}
                onChangeText={setQuery}
                style={styles.searchInput}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                multiline
                textAlignVertical="center"
              />
            </View>

            <TouchableOpacity activeOpacity={0.9} style={styles.resolveBtn} onPress={onResolve}>
              <Text style={styles.resolveText}>Resolve</Text>
            </TouchableOpacity>
          </View>

          {/* Resolved card */}
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Resolved Address</Text>

            <View style={styles.row}>
              <Text style={styles.label}>Quartier:</Text>
              <Text style={styles.value}>{resolved.quartier}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>Secteur:</Text>
              <Text style={styles.value}>{resolved.secteur}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>Sous-secteur:</Text>
              <Text style={styles.value}>{resolved.sousSecteur}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>Entrée:</Text>
              <Text style={styles.value}>{resolved.entree}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>Lieu:</Text>
              <Text style={styles.value}>{resolved.lieu}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>BANOC:</Text>
              <View style={styles.banocPill}>
                <Text style={styles.banocText}>{resolved.banoc}</Text>
              </View>
            </View>

            {/* IMPORTANT: Latitude/Longitude single values only */}
            <View style={styles.row}>
              <Text style={styles.label}>Latitude:</Text>
              <Text style={styles.value}>{Number(resolved.latitude).toFixed(5)}</Text>
            </View>

            <View style={styles.row}>
              <Text style={styles.label}>Longitude:</Text>
              <Text style={styles.value}>{Number(resolved.longitude).toFixed(5)}</Text>
            </View>

            <TouchableOpacity activeOpacity={0.9} style={styles.navBtn} onPress={onNavigate}>
              <Text style={styles.navIcon}>⌖</Text>
              <Text style={styles.navText}>Navigate to Location</Text>
            </TouchableOpacity>
          </View>

          {/* Spacer (like the mockup has a lot of breathing room) */}
          <View style={{ height: 220 }} />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {
    flex: 1,
    backgroundColor: "#E9ECF6",
  },
  scroll: {
    paddingBottom: 28,
  },
  screen: {
    paddingHorizontal: 18,
    paddingTop: 16,
  },

  header: {
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    marginBottom: 18,
    paddingHorizontal: 2,
  },
  logo: {
    width: 180,
    height: 50,
  },
  tagline: {
    marginTop: 4,
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.70)",
    fontSize: 16,
    fontWeight: "600",
    lineHeight: 22,
  },

  searchRow: {
    flexDirection: "row",
    alignItems: "stretch",
    gap: 10,
    marginBottom: 18,
  },
  searchInputWrap: {
    flex: 1,
    backgroundColor: "rgba(255,255,255,0.65)",
    borderRadius: 14,
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    paddingLeft: 40,
    paddingRight: 12,
    minHeight: 64,
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.06,
        shadowRadius: 10,
        shadowOffset: { width: 0, height: 6 },
      },
      android: { elevation: 2 },
    }),
  },
  searchIcon: {
    position: "absolute",
    left: 14,
    top: 18,
    fontSize: 20,
    color: "rgba(15, 23, 42, 0.45)",
  },
  searchInput: {
    fontSize: 18,
    fontWeight: "700",
    color: "#0F172A",
    lineHeight: 24,
    paddingVertical: 10,
  },

  resolveBtn: {
    width: 120,
    borderRadius: 14,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.10,
        shadowRadius: 12,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 4 },
    }),
  },
  resolveText: {
    color: "#FFFFFF",
    fontSize: 18,
    fontWeight: "800",
    letterSpacing: 0.2,
  },

  card: {
    backgroundColor: "rgba(255,255,255,0.65)",
    borderRadius: 18,
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    padding: 16,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.08,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 3 },
    }),
  },
  cardTitle: {
    fontSize: 22,
    fontWeight: "900",
    color: "#0F172A",
    marginBottom: 12,
  },

  row: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: 10,
  },
  label: {
    width: 120,
    color: "rgba(15,23,42,0.55)",
    fontSize: 18,
    fontWeight: "700",
  },
  value: {
    flex: 1,
    color: "#0F172A",
    fontSize: 18,
    fontWeight: "800",
  },

  banocPill: {
    backgroundColor: "rgba(46,89,183,0.12)",
    borderRadius: 10,
    paddingHorizontal: 10,
    paddingVertical: 6,
    borderWidth: 1,
    borderColor: "rgba(46,89,183,0.18)",
  },
  banocText: {
    color: "#2E59B7",
    fontSize: 16,
    fontWeight: "900",
    letterSpacing: 0.6,
  },

  navBtn: {
    marginTop: 14,
    height: 56,
    borderRadius: 14,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    flexDirection: "row",
    gap: 10,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.12,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 5 },
    }),
  },
  navIcon: {
    color: "#FFFFFF",
    fontSize: 20,
    marginTop: -1,
  },
  navText: {
    color: "#FFFFFF",
    fontSize: 20,
    fontWeight: "900",
    letterSpacing: 0.2,
  },
});
